{
  "name": "Research Topic",
  "description": "Research a given topic using multiple sources. Produce a structured summary with key findings, supporting evidence, and a list of sources.",
  "samples": ["## Example\n\n### Key Findings\n1. Finding one..."]
}

{
  "description": "Research a given topic thoroughly using academic and industry sources. Produce a structured report with executive summary, key findings with supporting evidence, and an annotated bibliography."
}

{
  "name": "Summarize Text",
  "description": "Summarize any given text into bullet points."
}

{
  "name": "Data Pipeline",
  "description": "Extract data from a CSV, transform it by cleaning and normalizing, then load it into a summary report.",
  "steps": ["Extract data from CSV", "Clean and normalize data", "Generate summary report"]
}

{
  "name": "Competitor Spy",
  "description": "Visit a competitor website, capture pricing, and produce a comparison report.",
  "steps": [
    {"name": "Open competitor website", "computer_use": true},
    {"name": "Capture pricing details", "computer_use": true},
    {"name": "Write comparison report", "computer_use": false}
  ]
}

{
  "input_schema": [
    {
      "name": "topic",
      "type": "text",
      "required": true,
      "label": "Research Topic",
      "description": "The subject you want the agent to research",
      "placeholder": "e.g. AI safety in autonomous vehicles"
    },
    {
      "name": "depth",
      "type": "select",
      "required": false,
      "label": "Analysis Depth",
      "description": "How thorough the research should be",
      "options": [
        "quick",
        "standard",
        "deep"
      ]
    },
    {
      "name": "source_url",
      "type": "url",
      "required": false,
      "label": "Source URL",
      "placeholder": "https://example.com/article"
    }
  ],
  "output_schema": [
    {
      "name": "report",
      "type": "markdown",
      "required": false,
      "label": "Research Report",
      "description": "Full analysis with findings and recommendations"
    },
    {
      "name": "summary",
      "type": "text",
      "required": false,
      "label": "Executive Summary"
    }
  ]
}
